callGraph.callee:
rows
    .map(function (row) {
      const m = String(row && row.medicamento ? row.medicamento : '').trim();
      const p = String(row && row.presentacion ? row.presentacion : '').trim();
      const d = String(row && row.dosis ? row.dosis : '').trim();
      if (!m && !p && !d) return '';
      return [m, p, d].filter(Boolean).join('  ·  ');
    })
    .filter
